/**
 * Reads the @modelcontextprotocol/ext-apps browser bundle (ESM),
 * transforms its `export{…}` into `globalThis.ExtApps={…}`,
 * and writes the result as a TS constant so Turbopack can bundle it
 * without needing runtime readFileSync + require.resolve.
 *
 * Runs as postinstall / prebuild.
 */
import { readFileSync, writeFileSync, mkdirSync } from 'node:fs'
import { createRequire } from 'node:module'
import { dirname, join } from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const require = createRequire(import.meta.url)

const outDir = join(__dirname, '..', 'lib', 'mcp', 'generated')
const outFile = join(outDir, 'ext-apps-bundle.ts')

let bundle
try {
  const raw = readFileSync(
    require.resolve('@modelcontextprotocol/ext-apps/app-with-deps'),
    'utf8',
  )
  bundle = raw.replace(/export\{([^}]+)\};?\s*$/, (_, body) =>
    'globalThis.ExtApps={' +
    body
      .split(',')
      .map((part) => {
        const [local, exported] = part.split(' as ').map((v) => v.trim())
        return `${exported ?? local}:${local}`
      })
      .join(',') +
    '};',
  )
  console.log(`[gen-ext-apps-bundle] transformed bundle: ${bundle.length} bytes`)
} catch (err) {
  console.error('[gen-ext-apps-bundle] failed to read ext-apps bundle:', err.message)
  bundle = 'globalThis.ExtApps={App:class{async connect(){}}};'
}

mkdirSync(outDir, { recursive: true })

const escaped = bundle.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$/g, '\\$')
writeFileSync(
  outFile,
  `// Auto-generated by scripts/gen-ext-apps-bundle.mjs — do not edit\nexport const extAppsBundle = \`${escaped}\`\n`,
)

console.log(`[gen-ext-apps-bundle] wrote ${outFile}`)
